      "cdi:name": {
        "@type": [
          "cdi:ObjectName"
        ],
        "cdi:name": "Integrated cross-country dataset"
      },
      "cdi:entityBound": {
        "@type": [
          "cdi:Reference"
        ],
        "cdi:uri": "https://doi.org/10.5281/zenodo.example-regional-employment-2025",
        "cdi:description": "Final harmonized and integrated regional employment dataset"
      }
    }
  ]
